exports.name = "lararium-bootstrap-sync";
exports.platforms = ["browser","node"];
exports.after = ["sync"];
exports.startup = function() {
  // Promote preloaded bootstrap plugins from plugin-shadow to regular wiki tiddlers.
  // Each plugin syncs as one package: the syncer sees the plugin container tiddler
  // as locally modified (changeCount incremented by addTiddler) and saves it via
  // saveTiddler → MemeSyncAdaptor → store.put() → CRDT.
  // Runs after the syncer initialises tiddlerInfo, so changeCount comparison works.
  var BOOTSTRAP_TAG = "$:/tags/LarariumBootstrap";
  var titles = $tw.wiki.filterTiddlers("[tag[" + BOOTSTRAP_TAG + "]]");
  titles.forEach(function(title) {
    var t = $tw.wiki.getTiddler(title);
    if (t) $tw.wiki.addTiddler(t.fields);
  });
};
